import anthropic, json

client = anthropic.Anthropic()

# --- Tool definitions ---
TOOLS = [
    {
        "name": "search",
        "description": "Search the web and return a short text summary.",
        "input_schema": {
            "type": "object",
            "properties": {
                "query": {"type": "string", "description": "The search query."},
            },
            "required": ["query"],
        },
    },
    {
        "name": "calculator",
        "description": "Evaluate a mathematical expression and return the result as a number.",
        "input_schema": {
            "type": "object",
            "properties": {
                "expression": {"type": "string", "description": "E.g. '23 * 47'"},
            },
            "required": ["expression"],
        },
    },
]

def dispatch_tool(name: str, inputs: dict) -> str:
    """Execute the tool and return a plain-text result (the Observation)."""
    if name == "search":
        # Stub: replace with a real search API call
        return f"[search result for '{inputs['query']}': George Orwell, 1949]"
    if name == "calculator":
        try:
            return str(eval(inputs["expression"], {"__builtins__": {}}))
        except Exception as e:
            return f"Error: {e}"
    return f"Unknown tool: {name}"

def react_loop(question: str, max_iterations: int = 8) -> str:
    """
    Run a ReAct loop: the model reasons, calls tools, observes results,
    and repeats until it produces a final answer.
    """
    messages = [{"role": "user", "content": question}]

    for _ in range(max_iterations):
        response = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=1024,
            tools=TOOLS,
            messages=messages,
        )

        # Append the assistant turn (may contain text Thought + tool_use Action)
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            # Model is done — extract the final text answer
            for block in response.content:
                if block.type == "text":
                    return block.text
            return "(no text answer produced)"

        # stop_reason == "tool_use" — execute each tool and collect Observations
        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                observation = dispatch_tool(block.name, block.input)
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": observation,
                })

        # Inject Observations as the next user turn
        messages.append({"role": "user", "content": tool_results})

    return "(max iterations reached)"


if __name__ == "__main__":
    answer = react_loop("Who wrote the novel 1984 and in what year was it published?")
    print(answer)

def print_react_trace(response_content: list) -> None:
    """Print a human-readable Thought / Action trace for debugging."""
    for block in response_content:
        if block.type == "text":
            print(f"[Thought] {block.text.strip()}")
        elif block.type == "tool_use":
            args = json.dumps(block.input, ensure_ascii=False)
            print(f"[Action ] {block.name}({args})")

import anthropic

client = anthropic.Anthropic()

def dispatch_tool_safe(name: str, inputs: dict) -> tuple[str, bool]:
    """Returns (observation_text, is_error)."""
    try:
        result = dispatch_tool(name, inputs)
        return result, False
    except Exception as exc:
        return f"Tool error: {exc}", True

def react_loop_with_error_handling(question: str, max_iterations: int = 10) -> str:
    messages = [{"role": "user", "content": question}]
    consecutive_errors = 0

    for _ in range(max_iterations):
        response = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=1024,
            tools=TOOLS,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            for block in response.content:
                if block.type == "text":
                    return block.text
            return "(no answer)"

        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                obs, is_error = dispatch_tool_safe(block.name, block.input)
                if is_error:
                    consecutive_errors += 1
                else:
                    consecutive_errors = 0
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": obs,
                    "is_error": is_error,
                })

        messages.append({"role": "user", "content": tool_results})

        if consecutive_errors >= 3:
            return "(tool errors prevented completion)"

    return "(max iterations reached)"

def extract_final_answer(content_blocks: list) -> str | None:
    """
    Try to extract a 'Final Answer: ...' from the last text block.
    Falls back to the full text if the prefix is absent.
    """
    for block in reversed(content_blocks):
        if block.type == "text":
            text = block.text.strip()
            if text.startswith("Final Answer:"):
                return text[len("Final Answer:"):].strip()
            return text  # answer without explicit label
    return None

# Usage inside the loop:
if response.stop_reason == "end_turn":
    answer = extract_final_answer(response.content)
    break
